$ErrorActionPreference = "Stop"

$project = "C:\Users\arauj\grafica-flash"

if (!(Test-Path -LiteralPath $project)) {
  Write-Host "Projeto nao encontrado em $project" -ForegroundColor Red
  exit 1
}

Set-Location $project

$utf8NoBom = New-Object System.Text.UTF8Encoding($false)

function Write-Base64File($relativePath, $base64Content) {
  $target = Join-Path $project $relativePath
  $directory = Split-Path $target -Parent
  New-Item -ItemType Directory -Force $directory | Out-Null
  $bytes = [System.Convert]::FromBase64String($base64Content.Trim())
  $content = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($target, $content, $utf8NoBom)
}

Write-Base64File "app\api\company\team\route.ts" @"

"@

Write-Base64File "app\painel\configuracoes\page.tsx" @"

"@

$painel = Join-Path $project "app\painel\page.tsx"

if (Test-Path -LiteralPath $painel) {
  $content = [System.IO.File]::ReadAllText($painel)

  if ($content -notmatch "/painel/configuracoes") {
    $link = @'

      <a
        href="/painel/configuracoes"
        className="rounded-2xl border border-blue-100 bg-white px-4 py-3 text-sm font-black text-[#05245c] transition hover:bg-blue-50"
      >
        Configurações
      </a>
'@

    if ($content -match "</header>") {
      $content = $content.Replace("</header>", "$link`n</header>")
      [System.IO.File]::WriteAllText($painel, $content, $utf8NoBom)
      Write-Host "Link de Configuracoes adicionado ao painel." -ForegroundColor Green
    }
  }
}

Remove-Item -Recurse -Force ".next" -ErrorAction SilentlyContinue

Write-Host "Pagina de configuracoes premium instalada." -ForegroundColor Green
Write-Host "Agora rode: npm run build" -ForegroundColor Yellow
